        $md += "## Consistently Failed Tests"
        $md += ""
        $md += "| Test Name | Failures |"
        $md += "|-----------|----------|"
        foreach ($ft in $failedTests) {
            $md += "| $($ft.Name) | $($ft.Count) |"
        }
        $md += ""
    }

    return $md -join "`n"
